5	export const ARTIFACTS_QUERY = gql`
6		query Artifacts($projectID: ID!, $first: Int, $after: String, $mediaType: String) {
7			artifacts(projectID: $projectID, first: $first, after: $after, mediaType: $mediaType) {
8				edges {
9					node {
10						id
11						path
12						title
13						mediaType
14						staleness
15					}
16					cursor
17				}
18				pageInfo {
19					hasNextPage
20					endCursor
21				}
22				totalCount
23			}
24		}
25	`
26	
27	export interface ArtifactNode {
28		id: string
29		path: string
30		title: string
31		mediaType: string
32		staleness: string
33	}
34	
35	export interface ArtifactEdge {
36		node: ArtifactNode
37		cursor: string
38	}
39	
40	export interface PageInfo {
41		hasNextPage: boolean
42		endCursor: string | null
43	}
44	
45	export interface ArtifactConnection {
46		edges: ArtifactEdge[]
47		pageInfo: PageInfo
48		totalCount: number
49	}
50	
51	interface ArtifactsResult {
52		artifacts: ArtifactConnection
53	}
54	
55	export const PAGE_SIZE = 50
56	
57	export const load: PageLoad = async ({ params, url, fetch }) => {
58		const mediaType = url.searchParams.get('mediaType') ?? null
59		const q = url.searchParams.get('q') ?? ''
60	
61		const client = createClient(fetch as unknown as typeof globalThis.fetch)
62		const data = await client.request<ArtifactsResult>(ARTIFACTS_QUERY, {
63			projectID: params.projectId,
64			first: PAGE_SIZE,
65			mediaType: mediaType ?? undefined
66		})
67		return {
68			nodeId: params.nodeId,
69			projectId: params.projectId,
70			artifacts: data.artifacts,
71			mediaType,
72			q
73		}
74	}
